<template>
  <div>
    <h2>这里是图管理</h2>
    <div @click="handleSelect">
      <span :data-tab="tab.id" v-for="tab in tabs" :key="tab.id" class="tab-item">
        {{ tab.label }}
      </span>
    </div>
    <div>
      <component :is="currentTab" />
    </div>

    <!-- <BashGraph /> -->
  </div>
</template>
<script setup lang="ts">
import { ref, shallowRef, watchEffect } from 'vue'
const tabId = ref<string>('apply-account')
const currentTab = shallowRef()
const tabs = [
  {
    id: 'bashGraph',
    label: 'Bash 图',
    component: () => import('./components/BashGraph.vue')
  },
  {
    id: 'apply-account',
    label: '申请账号图',
    component: () => import('./components/AccountApply.vue')
  }
]

const handleSelect = async (event: Event) => {
  const id = (event.target as HTMLElement).dataset.tab
  tabId.value = id || ''
}

watchEffect(async () => {
  console.log(tabId.value)
  if (tabId.value) {
    const tab = tabs.find(item => item.id === tabId.value)
    if (tab) {
      const component = await tab.component()
      currentTab.value = component.default
    }
  }
})

defineOptions({
  name: 'GraphIndexView'
})
</script>

<style scoped lang="less">
.tab-item {
  cursor: pointer;
  display: inline-block;
  padding: 5px 10px;
  border: 1px solid #ccc;
  border-radius: 5px;
  margin-right: 5px;
}
</style>
